const invoices = $input.all().map(i => i.json);
const flat = Array.isArray(invoices[0]) ? invoices[0] : invoices;

if (!flat || flat.length === 0 || !flat[0]?.id) {
  return [{ json: { has_overdue: false, count: 0, invoices: [] } }];
}

const today = new Date();
const enriched = flat.map(inv => {
  const dueDate = new Date(inv.invoice_date_due);
  const daysOverdue = Math.floor((today - dueDate) / (1000 * 60 * 60 * 24));
  return {
    id: inv.id,
    name: inv.name,
    partner: Array.isArray(inv.partner_id) ? inv.partner_id[1] : inv.partner_id,
    partner_id: Array.isArray(inv.partner_id) ? inv.partner_id[0] : inv.partner_id,
    invoice_date: inv.invoice_date,
    due_date: inv.invoice_date_due,
    days_overdue: daysOverdue,
    amount_total: inv.amount_total,
    amount_residual: inv.amount_residual,
    currency: Array.isArray(inv.currency_id) ? inv.currency_id[1] : 'PHP',
    account_manager_id: Array.isArray(inv.invoice_user_id) ? inv.invoice_user_id[0] : 17,
    account_manager: Array.isArray(inv.invoice_user_id) ? inv.invoice_user_id[1] : 'BOM',
    urgency: daysOverdue > 90 ? 'critical' : daysOverdue > 60 ? 'high' : daysOverdue > 30 ? 'medium' : 'low'
  };
});

return enriched.map(inv => ({ json: inv }));

const gptResponse = $input.first().json;
const emailBody = gptResponse.choices?.[0]?.message?.content || 'Please follow up on overdue payment.';
const invoice = $('Enrich Invoice Data').first().json;

return [{ json: {
  invoice_id: invoice.id,
  partner: invoice.partner,
  days_overdue: invoice.days_overdue,
  amount_residual: invoice.amount_residual,
  currency: invoice.currency,
  urgency: invoice.urgency,
  account_manager_id: invoice.account_manager_id,
  email_body: emailBody,
  activity_note: `**Collections Follow-up — ${invoice.name}**\n\nCustomer: ${invoice.partner}\nAmount Due: ${invoice.currency} ${invoice.amount_residual.toFixed(2)}\nDays Overdue: ${invoice.days_overdue}\nUrgency: ${invoice.urgency.toUpperCase()}\n\n---\n\n**Suggested Email:**\n${emailBody}`
}}];

const items = $input.all();
const count = items.length;
const totalAmount = items.reduce((s, i) => s + (i.json.amount_residual || 0), 0);

return [{ json: {
  status: 'ok',
  invoices_processed: count,
  total_overdue: totalAmount,
  message: `Processed ${count} overdue invoices, activities created`
}}];

